        CONSTRAINT "FK_Transactions_Loans_LoanId" FOREIGN KEY ("LoanId") REFERENCES "Loans" ("Id"),
        CONSTRAINT "FK_Transactions_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE CASCADE
