DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260611065556_Enum') THEN
        ALTER TABLE "Transactions"
        ALTER COLUMN "Type" DROP DEFAULT;

        ALTER TABLE "Transactions"
        ALTER COLUMN "Type" TYPE integer
        USING CASE lower("Type"::text)
            WHEN 'expense' THEN 1
            WHEN 'income' THEN 2
            WHEN 'transfer' THEN 3
            WHEN 'borrow' THEN 4
            WHEN 'lend' THEN 5

            WHEN 'chi' THEN 1
            WHEN 'thu' THEN 2
            WHEN 'chuyen_khoan' THEN 3
            WHEN 'vay' THEN 4
            WHEN 'cho_vay' THEN 5

            WHEN '10' THEN 4
            WHEN '11' THEN 5

            ELSE
                CASE
                    WHEN "Type"::text ~ '^[0-9]+$' THEN "Type"::integer
                    ELSE 1
                END
        END;

        ALTER TABLE "Transactions"
        ALTER COLUMN "Type" SET DEFAULT 1;
    END IF;
END $EF$;

